${SEP}'3i static void *ec_lsp(char *loc, char *cmd, char *arg)
{
	char ft[32];
	int n = 0;
	if (!*arg) {
		lsp_list();
		return NULL;
	}
	while (arg[n] && arg[n] != ' ' && n < (int)sizeof(ft) - 1) {
		ft[n] = arg[n];
		n++;
	}
	ft[n] = '\\0';
	while (arg[n] == ' ')
		n++;
	if (!arg[n])
		return \"lsp: missing server command\";
	lsp_register(ft, arg + n);
	lsp_dirty = 1;
	return NULL;
}

