static void vi_drawdiag(const char *diag, int sev, int r, int col)
{
	static const char *sevname[] = {\"info\", \"error\", \"warning\", \"info\", \"hint\"};
	if (col < 0 || col >= xcols)
		return;
	sbuf_smake(sb, 256)
	sbuf_str(sb, \"  \")
	sbuf_str(sb, sevname[sev > 0 && sev < 5 ? sev : 1])
