 				vc_status(0);
 				vi_mod |= 1;
 				break;
+			case 0:	/* lsp_wake yield; redraw via lsp_dirty */
+				break;
 			default:
 				continue;
 			}
@@ -1779,6 +1828,12 @@ void vi(int init)
 				}
 			}
 		}
+		if (xb_path && xb_path[0])
+			lsp_sync(xb_path, xb);
+		if (lsp_dirty) {
+			lsp_dirty = 0;
+			vi_mod |= 1;
+		}
 		term_record = 1;
 		if (vi_mod & 1 || xleft != oleft
 				|| (vi_lnnum && orow != xrow && !(vi_lnnum == 2))
